svg.script:
const path = document.querySelector('#triangle');
const sortByte = () => Math.floor(Math.random() * 256);
let rotate = 0;
const incRotate = () => {
    rotate += 90;
    if (rotate > 360) rotate -= 360;
}
path.addEventListener('click', (e) => {
    incRotate();
    e.target.setAttribute('transform', `rotate(${rotate} 100 100)`);
    e.target.setAttribute('fill', `rgb(${sortByte()}, ${sortByte()}, ${sortByte()})`);
});
